/*
 * Address field (vanilla JS port)
 * https://github.com/tableau-mkt/jquery.addressfield
 *
 * Licensed under the MIT license.
 */
(function (root) {
    "use strict";

    // WeakMap used in place of jQuery's $.data() for per-element storage.
    var savedValues = new WeakMap();

    /**
     * Initialise an address widget.
     *
     * @param {Element} container  The DOM element wrapping the address fields.
     * @param {Object}  options    Same shape as the original jQuery plugin options
     *                             (fields, json, async, defs).
     * @returns {Element} container
     */
    function addressfield(container, options) {
        var configs = Object.assign(
            { fields: {}, json: null, async: true, defs: { fields: {} } },
            options
        );
        var transformedData;

        if (typeof configs.json === "string") {
            fetch(configs.json)
                .then(function (res) { return res.json(); })
                .then(function (data) {
                    transformedData = addressfield.transform(data);
                    addressfield.initCountries(container, configs.fields.country, transformedData);
                    addressfield.binder(container, configs.fields, transformedData);
                    _trigger(container, configs.fields.country);
                });
            return container;
        }

        if (typeof configs.json === "object" && configs.json !== null) {
            transformedData = addressfield.transform(configs.json);
            addressfield.initCountries(container, configs.fields.country, transformedData);
            addressfield.binder(container, configs.fields, transformedData);
            _trigger(container, configs.fields.country);
            return container;
        }

        // Legacy: apply a one-time mutation without JSON config.
        return addressfield.apply(container, configs.defs, configs.fields);
    }

    /** Dispatch a change event on the country element to apply its config. */
    function _trigger(container, countrySelector) {
        var el = container.querySelector(countrySelector);
        if (el) el.dispatchEvent(new Event("change", { bubbles: true }));
    }

    /**
     * Apply a field configuration to an address container.
     *
     * @param {Element} container
     * @param {Object}  config    Country field config (has a .fields array).
     * @param {Object}  fieldMap  xNAL name → CSS selector mapping.
     * @returns {Element} container
     */
    addressfield.apply = function (container, config, fieldMap) {
        var fieldOrder = [];
        var pos, field, selector, el, placeholder;

        for (pos in config.fields) {
            if (!Object.prototype.hasOwnProperty.call(config.fields, pos)) continue;

            field    = addressfield.onlyKey(config.fields[pos]);
            selector = Object.prototype.hasOwnProperty.call(fieldMap, field)
                ? fieldMap[field]
                : "." + field;
            el = container.querySelector(selector);

            // Nested field group (e.g. locality containing localityname etc.)
            if (config.fields[pos][field] instanceof Array) {
                return addressfield.apply(
                    container.querySelector(selector) || container,
                    { fields: config.fields[pos][field] },
                    fieldMap
                );
            }

            if (el && Object.prototype.hasOwnProperty.call(fieldMap, field)) {
                fieldOrder.push(selector);

                if (typeof config.fields[pos][field].options !== "undefined") {
                    if (el.tagName !== "SELECT") {
                        el = addressfield.convertToSelect(el);
                    }
                    addressfield.updateOptions(el, config.fields[pos][field].options);
                } else {
                    if (el.tagName === "SELECT") {
                        el = addressfield.convertToText(el);
                    }
                    placeholder = Object.prototype.hasOwnProperty.call(config.fields[pos][field], "eg")
                        ? config.fields[pos][field].eg
                        : "";
                    addressfield.updateEg(el, placeholder);
                }

                addressfield.updateLabel(el, config.fields[pos][field].label);
            }

            if (el && !addressfield.isVisible(el) && Object.prototype.hasOwnProperty.call(fieldMap, field)) {
                addressfield.showField(el);
            }

            if (el) {
                addressfield.validate(el, field, config.fields[pos][field]);
            }
        }

        // Hide fields present in the fieldMap but absent from this country config.
        Object.keys(fieldMap).forEach(function (fieldName) {
            var fEl = container.querySelector(fieldMap[fieldName]);
            if (fEl && !addressfield.hasField(config, fieldName)) {
                addressfield.hideField(fEl);
            }
        });

        addressfield.orderFields(container, fieldOrder);

        container.dispatchEvent(new CustomEvent("addressfield:after", {
            detail: { config: config, fieldMap: fieldMap },
            bubbles: true,
        }));

        return container;
    };

    /**
     * Populate the country <select> with options from countryMap, but only if
     * it is currently empty (no <option> children).
     */
    addressfield.initCountries = function (container, selector, countryMap) {
        var countryEl = container.querySelector(selector);
        if (!countryEl || countryEl.options.length > 0) return;

        var defaultCountry = countryEl.getAttribute("data-country-selected");

        Object.keys(countryMap).forEach(function (iso) {
            var option = document.createElement("option");
            option.value = iso;
            option.textContent = countryMap[iso].label;
            if (defaultCountry && iso.toLowerCase() === defaultCountry.toLowerCase()) {
                option.selected = true;
            }
            countryEl.appendChild(option);
        });
    };

    /**
     * Bind a change handler to the country field so that selecting a country
     * applies the corresponding address field configuration.
     */
    addressfield.binder = function (container, fieldMap, countryConfigMap) {
        var countryEl = container.querySelector(fieldMap.country);
        if (countryEl) {
            countryEl.addEventListener("change", function () {
                addressfield.apply(container, countryConfigMap[this.value], fieldMap);
            });
        }
        return container;
    };

    /**
     * Transform the raw JSON (options array) into a map keyed by ISO country code.
     */
    addressfield.transform = function (data) {
        var countryMap = {};
        data.options.forEach(function (entry) {
            countryMap[entry.iso] = entry;
        });
        return countryMap;
    };

    /** Return the first (and only) key of an object. */
    addressfield.onlyKey = function (obj) {
        for (var key in obj) {
            if (Object.prototype.hasOwnProperty.call(obj, key)) return key;
        }
    };

    /** Return whether a config contains a given field name (recurses into arrays). */
    addressfield.hasField = function (config, expectedField) {
        var pos, field;
        for (pos in config.fields) {
            if (!Object.prototype.hasOwnProperty.call(config.fields, pos)) continue;
            field = addressfield.onlyKey(config.fields[pos]);
            if (config.fields[pos][field] instanceof Array) {
                return addressfield.hasField({ fields: config.fields[pos][field] }, expectedField);
            }
            if (field === expectedField) return true;
        }
        return false;
    };

    /** Update the <label> associated with el. */
    addressfield.updateLabel = function (el, label) {
        var labelEl = el.id
            ? document.querySelector('label[for="' + el.id + '"]')
            : el.previousElementSibling;
        if (labelEl) labelEl.textContent = label;
    };

    /** Set or clear the placeholder (e.g. hint) on an input. */
    addressfield.updateEg = function (el, example) {
        el.setAttribute("placeholder", example ? "e.g. " + example : "");
    };

    /** Replace the <select>'s options with new ones, restoring the previous value. */
    addressfield.updateOptions = function (el, options) {
        var oldVal = savedValues.has(el) ? savedValues.get(el) : el.value;
        el.innerHTML = "";
        options.forEach(function (optObj) {
            var value = addressfield.onlyKey(optObj);
            var option = document.createElement("option");
            option.value = value;
            option.textContent = optObj[value];
            el.appendChild(option);
        });
        el.value = oldVal;
        el.dispatchEvent(new Event("change", { bubbles: true }));
        savedValues.delete(el);
    };

    /** Replace a <select> with a plain text <input>, preserving its value. */
    addressfield.convertToText = function (el) {
        var input = document.createElement("input");
        input.type = "text";
        addressfield.copyAttrsTo(el, input);
        input.value = el.value;
        el.parentNode.replaceChild(input, el);
        return input;
    };

    /** Replace a text <input> with a <select>, saving the old value for later. */
    addressfield.convertToSelect = function (el) {
        var select = document.createElement("select");
        addressfield.copyAttrsTo(el, select);
        savedValues.set(select, el.value);
        el.parentNode.replaceChild(select, el);
        return select;
    };

    /**
     * Optional format validation. No-op unless extended by the consuming code
     * (address_form.js overrides this to mark fields required/optional).
     */
    addressfield.validate = function (el, field, config) {
        // No-op in the base implementation.
        // Override this method to add required indicators or custom validation.
    };

    /** Hide a field and its container. */
    addressfield.hideField = function (el) {
        el.value = "";
        el.style.display = "none";
        var c = addressfield.container(el);
        if (c) c.style.display = "none";
    };

    /** Show a field and its container. */
    addressfield.showField = function (el) {
        el.style.display = "";
        var c = addressfield.container(el);
        if (c) c.style.display = "";
    };

    /** Return true if el is currently visible in the layout. */
    addressfield.isVisible = function (el) {
        return el.offsetParent !== null && el.style.display !== "none";
    };

    /**
     * Return the nearest ancestor element that contains the label for el.
     * Falls back to el.parentElement.
     */
    addressfield.container = function (el) {
        if (!el) return null;
        var labelEl = el.id
            ? document.querySelector('label[for="' + el.id + '"]')
            : el.previousElementSibling;
        var parent = el.parentElement;
        while (parent) {
            if (labelEl && parent.contains(labelEl)) return parent;
            parent = parent.parentElement;
        }
        return el.parentElement;
    };

    /**
     * Copy a safe subset of attributes (class, id, name) from src to dst.
     */
    addressfield.copyAttrsTo = function (src, dst) {
        ["class", "id", "name"].forEach(function (attr) {
            var val = src.getAttribute(attr);
            if (val !== null) dst.setAttribute(attr, val);
        });
    };

    /**
     * Re-order field containers within container to match the given selector order.
     */
    addressfield.orderFields = function (container, order) {
        var containers = order.map(function (selector) {
            var el = container.querySelector(selector);
            return el ? addressfield.container(el) : null;
        }).filter(Boolean);

        // Detach then re-append in the correct order.
        containers.forEach(function (c) { c.remove(); });
        containers.forEach(function (c) { container.appendChild(c); });
    };

    // Expose globally.
    root.addressfield = addressfield;

    // Add the required flag to a specific field key within a fields array.
    function addRequiredToKey(fields, findKey) {
        fields.forEach(function (fieldObj) {
            var fieldName = Object.keys(fieldObj)[0];
            var data = fieldObj[fieldName];
            if (fieldName === findKey) {
                data.required = true;
            } else if (Array.isArray(data)) {
                addRequiredToKey(data, findKey);
            }
        });
    }

    // Hook into transform to mark fields listed in country.required as required.
    var oldTransform = addressfield.transform;
    addressfield.transform = function (data) {
        var mappedData = oldTransform.call(this, data);
        Object.keys(mappedData).forEach(function (key) {
            var country = mappedData[key];
            if (country.required && country.fields) {
                country.required.forEach(function (field) {
                    addRequiredToKey(country.fields, field);
                });
            }
        });
        return mappedData;
    };

    function labelFor(el) {
        return el.id ? document.querySelector('label[for="' + el.id + '"]') : null;
    }

    function makeFieldRequired(el) {
        el.setAttribute("required", "");
        var label = labelFor(el);
        if (label && !label.querySelector(".form__required")) {
            var span = document.createElement("span");
            span.className = "form__required";
            span.textContent = "*";
            label.appendChild(span);
        }
    }

    function makeFieldNotRequired(el) {
        el.removeAttribute("required");
        var label = labelFor(el);
        if (label) {
            var span = label.querySelector(".form__required");
            if (span) span.remove();
        }
    }

    // Hook into validate to update the required attribute and label indicator.
    var oldValidate = addressfield.validate;
    addressfield.validate = function (el, field, config) {
        if (config.required) {
            makeFieldRequired(el);
        } else {
            makeFieldNotRequired(el);
        }
        oldValidate.call(this, el, field, config);
    };

    // Hook into convertToSelect to wrap the new <select> in .form__select.
    var oldConvertToSelect = addressfield.convertToSelect;
    addressfield.convertToSelect = function (el) {
        var select = oldConvertToSelect.call(this, el);
        var wrapper = document.createElement("div");
        wrapper.className = "form__select";
        select.parentNode.insertBefore(wrapper, select);
        wrapper.appendChild(select);
        return select;
    };

    // Hook into convertToText to unwrap the input from .form__select.
    var oldConvertToText = addressfield.convertToText;
    addressfield.convertToText = function (el) {
        var input = oldConvertToText.call(this, el);
        var parent = input.parentNode;
        if (parent && parent.classList.contains("form__select")) {
            parent.parentNode.insertBefore(input, parent);
            parent.remove();
        }
        return input;
    };

    var FIELDS = {
        country:            "[data-js-addressfield-name='country']",
        thoroughfare:       "[data-js-addressfield-name='thoroughfare']",
        premise:            "[data-js-addressfield-name='premise']",
        locality:           "[data-js-addressfield-name='locality']",
        localityname:       "[data-js-addressfield-name='localityname']",
        administrativearea: "[data-js-addressfield-name='administrativearea']",
        postalcode:         "[data-js-addressfield-name='postalcode']",
    };

    document.addEventListener("DOMContentLoaded", function () {
        document.querySelectorAll(".form .address").forEach(function (container) {
            addressfield(container, {
                json: "/static/addressfield.min.json",
                fields: FIELDS,
            });
        });
    });

}(window));
